int main(){
int n,i,j=0,b,c;
scanf("%d",&n);
char a[n],d[n];
scanf("%s",a);
b=1;
c=2;
for(;;){
    d[j]=a[b-1];
    if(b==n)break;
    b+=c;
    c++;
    j++;
}
for(i=0;i<=j;i++){
printf("%c",d[i]);
}
