use std::io;

macro_rules! readln {
    () => {{
        use std::io;
        let mut buf = String::new();
        io::stdin().read_line(&mut buf).unwrap();
        buf.trim().to_string()
    }};
    ( $t:ty ) => {{
        let input = readln!();
        input.parse::<$t>().unwrap()
    }};
    ( $( $t:ty ),+ ) => {{
        let input = readln!();
        let mut input = input.split_whitespace();
        (
            $(
                input.next().unwrap().parse::<$t>().unwrap(),
            )+
        )
    }}
}

fn main() {
    readln!();
    let encoded = readln!();
    let encoded: Vec<char> = encoded.chars().collect();

    let mut decoded = String::with_capacity(10);
    let mut index = 0;
    let mut decoded_index = 0;
    while index < encoded.len() {
        decoded.push(encoded[index]);
        decoded_index += 1;

        index += decoded_index;
    }

    println!("{}", decoded);
}
